mapper.select:
SELECT id, code, name, description, scope_type, created_at, updated_at
FROM role
WHERE code = #{code}

SELECT u.id AS id, u.username AS username, u.display_name AS displayName, u.email AS email, u.enabled AS enabled, u.tenant_id AS tenantId, t.tenant_code AS tenantCode, t.name AS tenantName, r.code AS roleCode, r.name AS roleName, u.created_at AS createdAt, u.updated_at AS updatedAt FROM user_account u INNER JOIN tenant t ON t.id = u.tenant_id LEFT JOIN user_role ur ON ur.user_id = u.id LEFT JOIN role r ON r.id = ur.role_id WHERE u.deleted_at IS NULL AND u.scope_type = 'TENANT' AND u.tenant_id = #{tenantId}
AND (u.username ILIKE CONCAT('%', #{keyword}, '%') OR u.display_name ILIKE CONCAT('%', #{keyword}, '%') OR u.email ILIKE CONCAT('%', #{keyword}, '%'))
AND u.enabled = TRUE AND u.enabled = FALSE
AND r.code = #{roleCode}
ORDER BY u.created_at DESC, u.id DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(DISTINCT u.id) FROM user_account u LEFT JOIN user_role ur ON ur.user_id = u.id LEFT JOIN role r ON r.id = ur.role_id WHERE u.deleted_at IS NULL AND u.scope_type = 'TENANT' AND u.tenant_id = #{tenantId}
AND (u.username ILIKE CONCAT('%', #{keyword}, '%') OR u.display_name ILIKE CONCAT('%', #{keyword}, '%') OR u.email ILIKE CONCAT('%', #{keyword}, '%'))
AND u.enabled = TRUE AND u.enabled = FALSE
AND r.code = #{roleCode}
